// Supabase returns an array — split into individual items
const rows = Array.isArray($input.first().json)
  ? $input.first().json
  : [$input.first().json];

const forceRegenerate = $('Webhook — Receive FAQ Audio Job Request').item.json?.body?.force_regenerate === true;

const valid = rows.filter(row => {
  if (!row.id || !row.question || !row.answer) return false;
  // Skip if already published unless force_regenerate
  if (row.audio_url && !forceRegenerate) return false;
  // Skip very short answers (under 20 chars — likely test/placeholder data)
  if ((row.answer || '').trim().length < 20) return false;
  return true;
});

return valid.map(row => ({ json: row }));

const faq = $input.first().json;

// Clean answer text
const cleanAnswer = (faq.answer || '')
  .replace(/<[^>]+>/g, '')        // strip HTML
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&nbsp;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const cleanQuestion = (faq.question || '').replace(/<[^>]+>/g, '').trim();

// Build SSML — adds pauses, emphasis, natural pacing
const ssml = `<speak>
  <prosody rate="0.95" pitch="0st">
    <emphasis level="moderate">Question:</emphasis>
    <break time="300ms"/>
    ${cleanQuestion}
    <break time="700ms"/>
    <emphasis level="moderate">Answer:</emphasis>
    <break time="400ms"/>
    ${cleanAnswer}
    <break time="500ms"/>
  </prosody>
</speak>`;

const slugBase = cleanQuestion
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .substring(0, 50)
  .replace(/-$/, '');

return [{
  json: {
    ...faq,
    cleanQuestion,
    cleanAnswer,
    ssml,
    audioFilename: `faq-${faq.id}-${slugBase}.mp3`
  }
}];

// Google TTS returns base64 audioContent — decode to binary
const ttsResp  = $input.first().json;
const faqData  = $('Code — Build SSML for Each FAQ').item.json;

const base64Audio = ttsResp?.audioContent;
if (!base64Audio) {
  throw new Error(`Google TTS returned no audioContent for FAQ ID: ${faqData.id}`);
}

// Decode base64 to Buffer
const audioBuffer = Buffer.from(base64Audio, 'base64');

return [{
  json: { ...faqData },
  binary: {
    data: {
      data: audioBuffer,
      mimeType: 'audio/mpeg',
      fileName: faqData.audioFilename,
      fileExtension: 'mp3'
    }
  }
}];

const uploadResp = $input.first().json;
const faqData    = $('Code — Build SSML for Each FAQ').item.json;

const audioUrl =
  uploadResp?.url ??
  uploadResp?.data?.url ??
  uploadResp?.file?.url ??
  uploadResp?.link ?? '';

if (!audioUrl) throw new Error(`UploadToURL returned no URL for FAQ ID: ${faqData.id}`);

return [{
  json: {
    ...faqData,
    audioUrl,
    audioGeneratedAt: new Date().toISOString()
  }
}];

