parameters.jsCode:
// Collect all processed FAQs from this loop run
const allItems = $('Code — Capture Audio URL + Timestamp').all();

const processed = allItems.map(item => ({
  id:         item.json.id,
  question:   item.json.cleanQuestion,
  category:   item.json.category,
  audioUrl:   item.json.audioUrl,
  generatedAt: item.json.audioGeneratedAt
}));

// Build Teams Adaptive Card table rows
const tableRows = processed.map(p =>
  `| [${p.question.substring(0,45)}...](${p.audioUrl}) | ${p.category} | ▶ [Listen](${p.audioUrl}) |`
).join('\n');

const teamsCard = {
  type: 'message',
  attachments: [
    {
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
        type: 'AdaptiveCard',
        version: '1.4',
        body: [
          {
            type: 'TextBlock',
            text: `🎧 FAQ Audio Library Updated — ${processed.length} FAQ${processed.length !== 1 ? 's' : ''} Processed`,
            weight: 'Bolder',
            size: 'Medium',
            color: 'Accent'
          },
          {
            type: 'TextBlock',
            text: `Generated at: ${new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' })}`,
            isSubtle: true,
            spacing: 'None'
          },
          {
            type: 'FactSet',
            facts: [
              { title: 'Total FAQs processed', value: String(processed.length) },
              { title: 'Categories covered',   value: [...new Set(processed.map(p => p.category))].join(', ') || 'General' }
            ]
          },
          ...processed.slice(0, 8).map(p => ({
            type: 'ColumnSet',
            columns: [
              {
                type: 'Column', width: 'stretch',
                items: [{ type: 'TextBlock', text: p.question.substring(0, 60), wrap: true, size: 'Small' }]
              },
              {
                type: 'Column', width: 'auto',
                items: [{ type: 'TextBlock', text: p.category, isSubtle: true, size: 'Small' }]
              }
            ]
          })),
          processed.length > 8 ? {
            type: 'TextBlock',
            text: `...and ${processed.length - 8} more. Check Supabase for full list.`,
            isSubtle: true, size: 'Small'
          } : null
        ].filter(Boolean),
        actions: [
          {
            type: 'Action.OpenUrl',
            title: '🔗 View Support Page',
            url: 'https://YOUR_SUPPORT_SITE_URL/faq'
          },
          {
            type: 'Action.OpenUrl',
            title: '🗄️ Open Supabase',
            url: 'https://app.supabase.com/project/YOUR_SUPABASE_PROJECT_REF/editor'
          }
        ]
      }
    }
  ]
};

return [{
  json: {
    processed,
    processedCount: processed.length,
    teamsCard,
    summaryTimestamp: new Date().toISOString()
  }
}];

